patch:
--- a/priority_encoder.sv
+++ b/priority_encoder.sv
@@ -9,7 +9,7 @@ module priority_encoder_64bit(
   output reg [5:0] priority
 );

-  always @(data_in[63:32]) begin
+  always @(*) begin
     if (data_in[63]) priority = 6'd63;
     else if (data_in[62]) priority = 6'd62;
     else if (data_in[61]) priority = 6'd61;

before_code:
module priority_encoder_64bit(
  input [63:0] data_in,
  output reg [5:0] priority
);

  always @(data_in[63:32]) begin
    if (data_in[63]) priority = 6'd63;
    else if (data_in[62]) priority = 6'd62;
    else if (data_in[61]) priority = 6'd61;
    else if (data_in[0]) priority = 6'd0;
    else priority = 6'd0;
  end

endmodule

after_code:
module priority_encoder_64bit(
  input [63:0] data_in,
  output reg [5:0] priority
);

  always @(*) begin
    if (data_in[63]) priority = 6'd63;
    else if (data_in[62]) priority = 6'd62;
    else if (data_in[61]) priority = 6'd61;
    else if (data_in[0]) priority = 6'd0;
    else priority = 6'd0;
  end

endmodule
